VALUES
  ('optometrist-moex-00344', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '隱形眼鏡係屬列管之醫療器材，有關隱形眼鏡的販賣，下列何者正確？①驗光所必須申請醫療器材販賣', '["驗光所需申請醫療器材販賣業藥 商許可執照，方可經營隱形眼鏡販賣業務", "有合格驗光人員執業的驗光所，可經營隱形眼鏡販賣業務， 但僅限於屬於醫療器材第二級較低風險的隱形眼鏡", "驗光所只能裝配隱形眼鏡，任何狀況下絕對禁止 販賣隱形眼鏡", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00345', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光師繼續教育下列敘述何者正確？①經認可辦理繼續教育課程之驗光人員團體，未依計畫書收 費項目及金額收費，致生超收費用或擅立項目收費，經中央主管機關依規定廢止認可，其繼續教育課', '["醫事人員受懲戒處分應接受一定時數繼續教育者，不得以醫事人員執 業登記及繼續教育辦法所定應接受之繼續教育抵充", "經認可辦理繼續教育課程之驗光人員團體，因 規避、妨礙或拒絕中央主管機關查核，經中央主管機關依規定廢止認可，其繼續教育課程及積分，不 生採認之效果", "經認可辦理繼續教育課程之驗光人員團體，未依規定或計畫書審查繼續教育課程及 積分情節重大，經中央主管機關依規定廢止認可，其繼續教育課程及積分，不生採認之效果  ⑤繼續 教育專業品質、專業倫理、專業課程之積分數，合計至少十二點，其中應包括感染管制及性別議題之 課程；超過二十四點者，以二十四點計", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00346', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光人員考試之規定，下列敘述何者正確？①應考人有偽造或變造應考證件情事經考試前發現', '["參加驗光師考試應考人有冒名頂替情事者，依法將受到取消應考資格、扣 考、不予錄取或撤銷其考試及格資格等處分", "應考人曾受廢止驗光人員證書處分者，依法須滿五年 以上，方得再應本考試", "曾在醫療機構或眼鏡行從事驗光業務滿二年，並具專科以上學校畢業資格， 經中央主管機關審查合格者，得應驗光師特種考試", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00347', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依驗光人員法對驗光所廣告之規範，下列何者不是屬於得廣告之事項？', '["驗光所之名稱、開業執照字號、地址、電話及交通路線", "驗光人員之姓名及證書字號", "收費標準", "其他經中央主管機關公告容許登載或宣播事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00348', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '為確保驗光所驗光業務服務品質，驗光人員依法必須符合一定的要求，下列何者並非必要條件？', '["應申請執業登記", "應加入職業工會", "應接受繼續教育", "應定期更新執業執照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00349', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依驗光人員法第45條規定，若自行為未滿六歲之兒童驗光配鏡，或是發現視力不能矯正卻未將當事 人轉介至醫療機構者，應處：', '["新臺幣一萬元以上五萬元以下罰鍰；其情節重大者，並處二個月以上一年以下停業處分或廢止其執業 執照", "新臺幣二萬元以上十萬元以下罰鍰；其情節重大者，並處一個月以上一年以下停業處分或廢止其執業 執照", "新臺幣三萬元以上十五萬元以下罰鍰；其情節重大者，並處三個月以上一年以下停業處分或廢止其執 業執照", "新臺幣五萬元以上二十萬元以下罰鍰；其情節重大者，並處五個月以上一年以下停業處分或廢止其執 業執照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00350', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光人員停業或歇業之規定，下列何者正確？①應自事實發生之日起二十日內，報請原發執業執', '["停業：登記其停業日期及理由後，發還其執業執照", "歇業：註銷其執業登記，並收 回執業執照", "停業之期間，以一年為限；逾一年者，應辦理歇業", "僅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00351', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者特製眼鏡不在低視力患者輔具的補助範圍？', '["包覆式濾光眼鏡，可阻隔藍光及紫外光", "手持望遠鏡，放大倍率在二倍以上", "放大鏡，倍率應高於二倍及屈光度高於八", "菲涅爾透鏡（FresnelLens）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00352', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關執行業務紀錄下列敘述何者正確？①驗光所執行業務之紀錄應妥為保管並至少保存三年，違反者', '["驗光所執行醫師開具之照會單或醫囑單業務，應妥為保管並 至少保存七年；但未成年者之紀錄，至少應保存至其成年後七年以上始得銷燬", "驗光人員執行業務， 應製作紀錄，簽名或蓋章及加註出生年、月、日，並應依當事人要求，提供驗光結果報告及簽名或蓋章", "驗光所收取費用，應開給載明收費項目及金額之收據，違反者處新臺幣二萬元以上十萬元以下罰鍰 ⑤驗光所不得違反收費標準，超額或擅立項目收費，違反者處新臺幣二萬元以上十萬元以下罰鍰", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00353', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關全體驗光人員業務範圍，下列敘述何者正確？①經廢止驗光人員執業執照未滿一年者，不得發給', '["驗光人員執行業務，發現視力不能矯正至正常者，應轉介至醫療機 構診治，違反者處新臺幣三萬元以上十五萬元以下罰鍰", "驗光人員對於因業務而知悉或持有他人秘 密不得無故洩漏，違反者處新臺幣二萬元以上十萬元以下罰鍰", "驗光人員應向執業所在地主管機關 申請執業登記，領有執業執照，始得執業。並應每六年接受一定時數之繼續教育，始得辦理執業執照 更新  ⑤驗光人員執業以一處為限，並應在所在地主管機關核准登記或其他經中央主管機關認可之機 構為之。但機構間之支援或經事先報准者，不在此限", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 48, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
